        log.println("Compressing " + size / MB + " MB at " +
                new java.sql.Time(startMs).toString());
        InputStream in = getDirectoryInputStream(fromDir);
        String temp = toFile + ".temp";
        OutputStream out =
                new BufferedOutputStream(
